class LinearProbingHashTable:
    def __init__(self, size):
        self.size = size
        self.table = [None] * size
        self.tombstone = object()  # Marker for deleted keys

    def hash(self, key):
        return key % self.size

    def insert(self, key, value):
        index = self.hash(key)

        for i in range(self.size):
            probe = (index + i) % self.size

            if self.table[probe] is None or self.table[probe] is self.tombstone:
                self.table[probe] = (key, value)
                return True

            if self.table[probe][0] == key:
                self.table[probe] = (key, value)
                return True

        return False  # Table is full

    def search(self, key):
        index = self.hash(key)

        for i in range(self.size):
            probe = (index + i) % self.size

            if self.table[probe] is None:
                return None  # Not found

            if self.table[probe] is not self.tombstone:
                if self.table[probe][0] == key:
                    return self.table[probe][1]

        return None

    def delete(self, key):
        index = self.hash(key)

        for i in range(self.size):
            probe = (index + i) % self.size

            if self.table[probe] is None:
                return False

            if self.table[probe] is not self.tombstone:
                if self.table[probe][0] == key:
                    self.table[probe] = self.tombstone
                    return True

        return False

class DoubleHashingHashTable {
    private int size;
    private String[] table;
    private final String TOMBSTONE = "DELETED";

    public DoubleHashingHashTable(int size) {
        this.size = size;
        this.table = new String[size];
    }

    // Primary hash function
    private int hash1(int key) {
        return key % size;
    }

    // Secondary hash function - must not return 0
    private int hash2(int key) {
        return 7 - (key % 7);  // Prime smaller than size
    }

    // Probe function for double hashing
    private int probe(int key, int i) {
        return (hash1(key) + i * hash2(key)) % size;
    }

    public boolean insert(int key, String value) {
        for (int i = 0; i < size; i++) {
            int index = probe(key, i);

            if (table[index] == null || table[index].equals(TOMBSTONE)) {
                table[index] = value;
                return true;
            }
        }
        return false;
    }

    public String search(int key, String target) {
        for (int i = 0; i < size; i++) {
            int index = probe(key, i);

            if (table[index] == null) {
                return null;
            }

            if (!table[index].equals(TOMBSTONE) && table[index].equals(target)) {
                return table[index];
            }
        }
        return null;
    }
}
